# Use localhost exception to create admin user (no auth needed from within the pod via localhost)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh admin --quiet --eval '
db.createUser({
  user: "admin",
  pwd: "admin123password",
  roles: [
    { role: "root", db: "admin" }
  ]
})
' 2>&1

